import{_ as e,o as a,c as t,j as r,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"葬仪堂","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/1.生理类/葬仪堂.md","filePath":"4.资源分区/1.血统与训练/1.生理类/葬仪堂.md"}'),s={name:"4.资源分区/1.血统与训练/1.生理类/葬仪堂.md"};function o(d,b,l,_,i,c){return a(),t("div",null,[...b[0]||(b[0]=[r("h1",{id:"葬仪堂",tabindex:"-1"},[p("葬仪堂 "),r("a",{class:"header-anchor",href:"#葬仪堂","aria-label":'Permalink to "葬仪堂"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘001D")])])],-1),n('<h1 id="葬仪堂-1" tabindex="-1">葬仪堂 <a class="header-anchor" href="#葬仪堂-1" aria-label="Permalink to &quot;葬仪堂&quot;">​</a></h1><p>葬仪堂<br> 前提：学识技能3级或以上。<br> 描述：葬仪堂，于现代或可称之为“殡仪馆”，意在操办葬仪之礼事，给予失去死者最后的体面，也寄托了生者活人的心意。<br> 在那个无暗之日亦是落下的时代，妖魔并起，百鬼夜行，死者连尸体也要遭到亵渎，化作憎恶生者之物横行于世，那是何等的末法时代。<br> 唯有历代葬仪堂主所传承之血脉，所持之法门，令死者重归尘土，度尽应死而未死者，能使得死者得到应有的尊重，在每次葬仪之行走过繁灯落尽的街道，都被生者托付了极大的期盼。</p><p>D级：赤团开时斜飞去<br> 描述：丧葬白事，乃是凡人最后的体面，也是人生画卷的终笔者。<br> 葬仪之行门道繁多——停灵守灵，落葬之法，牌位器具…以上种种环节都有着严苛的规矩，缺一者则无有令死者安息之法门，而无论逝者出身贵贱，财富多寡，都要应他们置办一场合适的葬礼。<br> 葬仪枪法：「枪开黄泉路，蝶引来世桥。」——这是葬仪堂秘传枪法的要引口诀，枪法大开大合，旨在快速超度死者重新回归尘土，是堂内仪倌弟子皆有修习的必要法门，有着杀伤诡怪妖魔之能。<br> 你以枪分类的武器进行攻击时，攻击视为具有【法破】特性，同时在攻击上获得2DP的技艺加值。</p><p>阴阳边界：由历代葬仪堂堂主亲自管理的机密之地，相传，人们能在那里见到去世的亲属与心愿未竟的亡魂，此时或为真可为假，但无论如何，这份传承的血脉确实能够使你看到一些“东西”。<br> 因此，你获得灵感视觉。</p><p>C级：最不安神晴又复雨<br> 描述：「我们葬仪堂，收活人的钱，送死人上路，肩负双倍的责任，须让阴阳两界的人满意。」<br> 说起堂里规矩，道行万千，堂主每到白天闭门停业，便常为年轻仪倌弟子们说书讲学。<br> 葬仪堂经营稳定，施礼得当，也是那个时代中所必不可缺的存在。</p><p>血之灶火：人初大灶，顺天应人，熊熊薪火，阴阳永续。<br> 葬仪堂主讲究个火葬，据说是祖师爷乃是灶王爷一脉所流传下来的术法，是死者安息的最佳手段。<br> 自由动作启动，你的周身燃烧起淡淡的血红火焰，这使你在进行攻击时伤害类型改为火焰伤害，同时可以点燃可燃物，因此在森林使用的时候会引发森林火灾。<br> 在以枪分类的武器进行攻击时，攻击时还会附带1点不可豁免的燃烧点数。<br> 若在攻击中具有“血之灶火”时，被这种方式杀死的单位尸身将会燃烧殆尽，同时视为承受了B级禁止复活的效果。</p><p>B级：逗留采血色，伴君眠花房<br> 描述：历代葬仪堂主，皆会亲手在堂中栽下一株血梅花树，历至今，后院中有七十七棵梅花树，每到夜晚便会红艳艳的绽放开来，行程一抹摇曳的色彩。<br> 或无人或有人可知，每一颗血梅花的绽放，都意味着一位葬仪堂主魂归故里，如此这般，所绽放开的花蕾因极具通灵的性质，是作符作物的极好乃至于绝佳材料。</p><p>血梅花：你亲手在主神空间栽下一刻血色梅花树，每经过一场影片，你都会获得一朵价值2000分的“血梅花”，必须消耗掉上一朵“血梅花”才能获得下一朵。<br> 不过，如果你能够将队友的尸体带回树下，每掩埋一具尸体就能够额外获得一朵“血梅花”，这包括了你自己的尸体，也就是意味着他人可以在你的允许下，在你死后依旧利用这颗梅花树，但一个主神空间内只能存在一颗血色梅花树。<br> 此外还能通过支付切实分数的的形式，以在主神处购买肥料来提高产生血梅花的质量，如果ST允许，影片中也能找到特定肥料用以代替。<br> 每支付575分数，可提高产出血梅花价值的250分。<br> 血梅花寄托了往日历代葬以堂主（或者你的队友）的记忆与魂魄，其中有着许多有价值的知识，使用血梅花就意味着去承载对应的记忆与魂魄的重量，当然你也可以单纯的用来泡茶喝，如此暴殄天物的味道也有对应分数的等级，或者在影片之中作为等价物进行金钱交易。</p><p>以葬仪堂主所通晓的特殊形式来使用血梅花后，这朵血梅花价值每有750分，你就可以选择任意一项技能提升1级，每有250分，你就可以选择任意一项专业提升1级，两者合计分数价值不能超过血梅花本身价值。</p><p>由于阴阳两隔，纵然藉由血梅花为引，历代葬仪堂主也注定命里有莫大劫数，冥冥之中受阴魂所影响，因此意志检定减少10DP，同时生命上限减少1点，视为身托阴魂的侵蚀。</p><p>葬仪枪法-皆传：枪开黄泉路，蝶引来世桥。生老病死，天地万象，尽在其中。<br> 枪如黄泉红蝶翩翩起舞，自有彼岸花，来世桥，牵动生者死者一身精气神，引向生老病死之流，哪怕死者也不能够避免。<br> 纵然出枪时的景色美轮美奂，却仍不折不扣的是一门极具杀伤力的与威能的度化之技。<br> 每次攻击命中后，目标失去二十年的寿命（可能得加个豁免对抗），至多令受影响目标的寿命上限减少二分之一，这是一个B级时间来源的衰老效果。</p><p>A级：无可奈何燃花作香<br> 描述：在堂主看来，那些早已逝去，却被囚浮世不得解脱，是至苦的受难者，而那些忤逆生死戒律的观念，也实难苟同。<br> 世间阴阳有序，命运无常，死亡难以预测，有应当它的规矩，无论何时何地，无论有何原因，都不该轻易挑衅「死」之一事。唯有认识它、尊重它，才能明白活着的价值。</p><p>蝶火燎原：<br> 通常来说，葬仪堂主最看不得的就是应当归于尘土之物仍在世间活蹦乱跳，越是这样她就越焦虑，越是焦虑她的火力就越大，似乎只有将这些事物彻底火葬，方能够安心定神下来。<br> 每当这个时候，她手中的那一杆长枪，所施展出的葬仪枪法，都会如同燎原烈火般席卷万千妖魔，又如同缥缈红蝶，引入世黄泉路。<br> 以自由动作启动，你的攻击射程增加480米，攻击视为范围攻击，同时对周身圆形范围内所有敌人造成伤害，以反射进行豁免。<br> 此时，你的攻击伤害可转换为燃烧点数。</p><p>血梅香：血梅花是历代葬仪堂主的思念，血梅花是历代葬仪堂主的记忆，血梅花更是那个时代葬仪堂主的缩影，寄托了葬仪堂的魂之所在。<br> 在这个终结了黑暗的时代，已经不再需要葬仪堂一代又一代的传承，作为新一任的葬仪堂主，你有权摆脱这般的宿命。<br> 当你死亡时，若这个世界内有任意单位携带了血梅花（除非ST允许，否则必须是B级栽种的血梅花树出产的花朵），则一缕魂魄寄托于血梅花之上。若没有，队友如果能把你的尸体带回主神空间，栽于梅花树下，你也可以魂寄梅花树。<br> 此时，你视为灵体状态，只能够观察外界或操作血梅花以你的基础移动速度进行移动，血梅花/梅花树会为你提供全遮蔽效果，而血梅花视为同血统等级价格的物品计算硬度和生命值，若血梅花被破坏，你立刻死亡。<br> 但如果没有被破坏，则在七天后你会重塑肉身并复活，这是一个A级别、幻象来源的复活效果。</p><p>专属物品<br> 乾坤泰卦帽<br> 本质：魔幻本质<br> 价格：250<br> 分类：头盔<br> 体积：1<br> 描述：帽子的材质偏硬，正面饰有葬仪堂的徽记。<br> 据说，此帽为葬仪堂主的标志性饰物，有法力，正阳克邪，保平安。<br> 哪怕妖风再大，惹了一身污浊，帽子一尘不染也依旧会一尘不染。<br> 帽子侧边的梅花，则摘自堂主亲手栽种的梅树。<br> 制法如下：取鲜花风干、刷色、过油，巧笔勾勒后晾晒三日，可成玲珑饰物。触手如柔雾，闻之有幽香。<br> 乾坤泰卦：你的机运检定结果上增加1点。<br> 不染尘埃：这个帽子不会脏污，如果没有特殊能力影响，则一直保持在洁净的状态。</p><p>血脉精萃<br> 本质：魔幻本质<br> 价格：C+1000<br> 分类：消耗品<br> 体积：忽略不计<br> 描述：历代葬仪堂主所传承的血脉，有诸邪退散，百鬼辟易之能。葬于血色梅花树下之时，一身精血凝结于此，状八面三方，不可置于无光之处，反之则有大恐怖现。<br> 效果：购买服用后失去血统B级中的负面效果，且所有感知到你的角色将会感受到源自血脉的压制，犹如煌煌天威，充斥了肃杀至凶之气，因此在被你攻击到时获得1点不可豁免的恐惧异常点数，你也可以选择对特定角色不生效。<br> 选开：非妖鬼之流，作恶之人不会感受到气息，也不会承受恐惧异常点数。<br> 选开：本物品若放置在无光之处超过6秒，立刻转变为一个战斗力以C级标准的或你本身战斗力取高，不分敌我的敌人，外观与实际特性由ST自定义。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',18)])])}const T=e(s,[["render",o]]);export{f as __pageData,T as default};
